    def transcript_source(self, request, pk):
         """Get the lowest quality video source for the transcript."""
        video = self.get_object()

         # Check if the request comes from a runner job
        if not RunnerJob.objects.filter(
            runner__runnerToken=request.data.get("runnerToken"), processingJobToken=request.data.get("jobToken")
         ).exists():
            return Response({"detail": "RunnerJob not found."}, status=HTTPStatus.FORBIDDEN)

         # Get the lowest quality video source
        serializer = self.get_serializer(video)

        video_urls  = serializer.data["urls"]["mp4"]
        if not video_urls:
            return Response({"detail": "No video source available for this video."}, status=HTTPStatus.NOT_FOUND)

         # Redirect to the lowest quality video source
        video_url = video_urls[max(video_urls)]

        return redirect(video_url, permanent=True)

